using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    Task<List<Department>> GetDepartmentsAsync();
    Task<Department?> GetDepartmentAsync(int id);
    Task<List<Course>> GetCoursesAsync(string? searchTerm = null, int? departmentId = null, int? credits = null);
    Task<Course?> GetCourseAsync(int id);
    Task<List<Course>> GetFeaturedCoursesAsync();
    Task<bool> SubmitEnrollmentAsync(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class InMemoryCatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public InMemoryCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and human civilization." }
        };

        var instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen has over 15 years of experience in software engineering and distributed systems. She received her Ph.D. from MIT and has published extensively on cloud computing architectures.", Email = "achen@university.edu", OfficeLocation = "Science Hall 301" },
            new() { Id = 2, Name = "Dr. Robert Kim", Title = "Associate Professor", Bio = "Dr. Kim specializes in machine learning and artificial intelligence. He previously worked at Google Research before joining the university faculty.", Email = "rkim@university.edu", OfficeLocation = "Science Hall 205" },
            new() { Id = 3, Name = "Dr. Maria Lopez", Title = "Professor", Bio = "Dr. Lopez is a renowned mathematician whose work on topology has been recognized with multiple national awards. She is passionate about making mathematics accessible to all students.", Email = "mlopez@university.edu", OfficeLocation = "Math Building 102" },
            new() { Id = 4, Name = "Dr. James Wright", Title = "Assistant Professor", Bio = "Dr. Wright is an experimental physicist specializing in quantum optics. His lab has made breakthrough discoveries in photon entanglement.", Email = "jwright@university.edu", OfficeLocation = "Physics Lab 410" },
            new() { Id = 5, Name = "Prof. Sarah Davis", Title = "Professor", Bio = "Prof. Davis is an award-winning author and literary critic. She has published three novels and edited several anthologies of contemporary American poetry.", Email = "sdavis@university.edu", OfficeLocation = "Humanities 208" },
            new() { Id = 6, Name = "Dr. Michael Torres", Title = "Associate Professor", Bio = "Dr. Torres is a historian of early modern Europe with particular expertise in the Renaissance period. He leads the university's study-abroad program in Florence.", Email = "mtorres@university.edu", OfficeLocation = "Humanities 315" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "An introductory course covering fundamental concepts of programming, data structures, and algorithmic thinking. Students will learn to write programs in Python and gain a solid foundation for further study in computer science.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Room = "Science Hall 110", IsFeatured = true, DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0] },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "A deep dive into essential data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Prerequisite: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", Room = "Science Hall 112", IsFeatured = false, DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0] },
            new() { Id = 3, Code = "CS 310", Title = "Machine Learning Fundamentals", Description = "Introduction to supervised and unsupervised learning, neural networks, and model evaluation. Students will complete hands-on projects using real-world datasets.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Room = "Science Hall 205", IsFeatured = true, DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1] },
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Math Building 101", IsFeatured = false, DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2] },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Essential for students in mathematics, physics, and computer science.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Room = "Math Building 103", IsFeatured = true, DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2] },
