            new() { Id = 10, Code = "ENG 250", Title = "American Literature Survey", Description = "A survey of major works in American literature from the colonial period to the present, exploring themes of identity, democracy, and cultural change.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Room = "Humanities 210", IsFeatured = false, DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4] },
