@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="px-4 py-5 text-center bg-primary text-white rounded-3 mb-4">
    <h1 class="display-5 fw-bold">University Course Catalog</h1>
    <p class="lead mb-3">Explore our departments and courses for the upcoming semester.</p>
    <a href="/catalog" class="btn btn-light btn-lg">Browse All Courses</a>
</div>

@if (_featuredCourses is not null)
{
    <section class="mb-5">
        <h2 class="mb-3">Featured Courses</h2>
        <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
            @foreach (var course in _featuredCourses)
            {
                <div class="col">
                    <CourseCard Course="course" />
                </div>
            }
        </div>
    </section>
}

@if (_departments is not null)
{
    <section>
        <h2 class="mb-3">Departments</h2>
        <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
            @foreach (var dept in _departments)
            {
                <div class="col">
                    <a href="/catalog?departmentId=@dept.Id" class="text-decoration-none">
                        <div class="card h-100 border-primary">
                            <div class="card-body">
                                <h5 class="card-title text-primary">@dept.Name</h5>
                                <p class="card-text text-muted">@dept.Description</p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    </section>
}

@code {
    private List<Course>? _featuredCourses;
    private List<Department>? _departments;

    protected override async Task OnInitializedAsync()
    {
        _featuredCourses = await CatalogService.GetFeaturedCoursesAsync();
        _departments = await CatalogService.GetDepartmentsAsync();
    }
}

@page "/catalog"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@rendermode InteractiveServer
@inject ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<CatalogFilters Departments="_departments" OnFiltersChanged="HandleFiltersChanged" />

@if (_courses is null)
{
    <p class="text-muted">Loading courses…</p>
}
else if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @_courses.Count course(s)</p>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in _courses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
}

@code {
    private List<Course>? _courses;
    private List<Department> _departments = new();

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        _departments = await CatalogService.GetDepartmentsAsync();
        _courses = await CatalogService.GetCoursesAsync(departmentId: DepartmentId);
    }

    private async Task HandleFiltersChanged((string? Search, int? DepartmentId, int? Credits) filters)
    {
        _courses = await CatalogService.GetCoursesAsync(filters.Search, filters.DepartmentId, filters.Credits);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted</h4>
        <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for <strong>@_selectedCourseTitle</strong> has been received.</p>
        <hr />
        <a href="/catalog" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-6">
            <EditForm Model="_model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
                <DataAnnotationsValidator />
                <AntiforgeryToken />
                <ValidationSummary class="text-danger mb-3" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="_model.StudentName" />
                    <ValidationMessage For="() => _model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" placeholder="e.g., CS123456" />
                    <ValidationMessage For="() => _model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="0">— Select a course —</option>
                        @if (_courses is not null)
                        {
                            @foreach (var course in _courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                            }
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Request</button>
                <a href="/catalog" class="btn btn-outline-secondary ms-2">Cancel</a>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course>? _courses;
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _courses = await CatalogService.GetCoursesAsync();

        if (CourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = CourseId.Value;
        }
    }

    private async Task HandleSubmit()
    {
        var success = await CatalogService.SubmitEnrollmentAsync(_model);
        if (success)
        {
            _selectedCourseTitle = _courses?.FirstOrDefault(c => c.Id == _model.CourseId)?.Title ?? "the selected course";
            _submitted = true;
        }
    }
}

